define i8 @known_power_of_two_lshr_add_one_allow_zero(i8 %x, i8 %y) {
  %1 = lshr i8 -1, %x
  %p = add i8 %1, 1
  %r = urem i8 %y, %p
  ret i8 %r
}

define i8 @trunc_is_pow2_or_zero(i16 %x, i8 %y) {
  %xp2 = shl i16 4, %x
  %xx = trunc i16 %xp2 to i8
  %r = urem i8 %y, %xx
  ret i8 %r
}

